class Solution {
public:
    int maxSubstrings(string word) {
        int n = word.size();
        vector<vector<bool>> dp(n, vector<bool>(n, false));
        int res = 0;
        for (int len = 4; len <= n; len++) {
            for (int i = 0; i <= n - len; i++) {
                int j = i + len - 1;
                if (word[i] == word[j]) {
                    if (len == 4) dp[i][j] = true;
                    else {
                        bool flag = true;
                        for (int k = i; k < j; k++) {
                            if (dp[i][k] || dp[k + 1][j]) {
                                flag = false;
                                break;
                            }
                        }
                        dp[i][j] = flag;
                    }
                    if (dp[i][j]) res++;
                }
            }
        }
        return res;
    }
};
